import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define custom CUDA kernel for optimized tall-skinny matrix multiplication
tall_skinny_matmul_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>

// Optimized kernel for A(M,K) * B(K,N) where M=16384, K=16, N=16384
// Using shared memory tiling and register blocking
__global__ void tall_skinny_matmul_kernel(
    const float* __restrict__ A,  // shape: [M, K] where K=16
    const float* __restrict__ B,  // shape: [K, N] where K=16
    float* __restrict__ C,        // shape: [M, N]
    int M, int K, int N
) {
    // Tile sizes
    const int TILE_M = 64;
    const int TILE_N = 64;

    // Block dimensions
    const int BLOCK_SIZE = 256;
    const int THREADS_PER_ROW = TILE_M / 4;  // 16 threads handle one row
    const int THREADS_PER_COL = TILE_N / 4;  // 16 threads handle one column

    // Shared memory for A and B tiles
    __shared__ float A_tile[TILE_M][16];
    __shared__ float B_tile[16][TILE_N];

    // Thread indices
    int tid = threadIdx.x;
    int block_row = blockIdx.y * TILE_M;
    int block_col = blockIdx.x * TILE_N;

    // Each thread handles 4x4 elements
    int thread_row = (tid / THREADS_PER_COL) * 4;
    int thread_col = (tid % THREADS_PER_COL) * 4;

    // Global row/col indices for this thread
    int global_row = block_row + thread_row;
    int global_col = block_col + thread_col;

    // Register accumulators for 4x4 output tile
    float accum[4][4] = {{0.0f}};

    // Loop over K dimension in chunks of 16
    for (int k_step = 0; k_step < K; k_step += 16) {
        // Load A tile into shared memory (coalesced)
        #pragma unroll
        for (int i = 0; i < 4; i++) {
            int load_row = block_row + thread_row + i;
            int load_k = k_step + (tid % 16);

            if (load_row < M && load_k < K) {
                A_tile[thread_row + i][tid % 16] = A[load_row * K + load_k];
            } else if (load_k < K) {
                A_tile[thread_row + i][tid % 16] = 0.0f;
            }
        }

        // Load B tile into shared memory (coalesced)
        #pragma unroll
        for (int j = 0; j < 4; j++) {
            int load_col = block_col + thread_col + j;
            int load_k = k_step + (tid / 16);

            if (load_k < K && load_col < N) {
                B_tile[tid / 16][thread_col + j] = B[load_k * N + load_col];
            } else if (load_k < K) {
                B_tile[tid / 16][thread_col + j] = 0.0f;
            }
        }

        __syncthreads();

        // Compute partial matrix multiplication
        #pragma unroll
        for (int k = 0; k < 16; k++) {
            // Load A values for this thread
            float a_vals[4];
            #pragma unroll
            for (int i = 0; i < 4; i++) {
                a_vals[i] = A_tile[thread_row + i][k];
            }

            // Load B values for this thread
            float b_vals[4];
            #pragma unroll
            for (int j = 0; j < 4; j++) {
                b_vals[j] = B_tile[k][thread_col + j];
            }

            // Update accumulators
            #pragma unroll
            for (int i = 0; i < 4; i++) {
                #pragma unroll
                for (int j = 0; j < 4; j++) {
                    accum[i][j] += a_vals[i] * b_vals[j];
                }
            }
        }

        __syncthreads();
    }

    // Write results to global memory
    #pragma unroll
    for (int i = 0; i < 4; i++) {
        #pragma unroll
        for (int j = 0; j < 4; j++) {
            int row = global_row + i;
            int col = global_col + j;

            if (row < M && col < N) {
                C[row * N + col] = accum[i][j];
            }
        }
    }
}

torch::Tensor optimized_matmul_cuda(torch::Tensor A, torch::Tensor B) {
    auto sizes_A = A.sizes();
    auto sizes_B = B.sizes();

    int M = sizes_A[0];
    int K = sizes_A[1];
    int N = sizes_B[1];

    // Create output tensor
    auto C = torch::zeros({M, N}, A.options());

    // Special optimized case for 16384x16 * 16x16384
    if (M == 16384 && K == 16 && N == 16384) {
        // Configure grid and block
        dim3 block_size(256);  // 256 threads per block
        dim3 grid_size((N + 63) / 64, (M + 63) / 64);  // ceil(N/64) x ceil(M/64)

        // Launch kernel
        tall_skinny_matmul_kernel<<<grid_size, block_size>>>(
            A.data_ptr<float>(),
            B.data_ptr<float>(),
            C.data_ptr<float>(),
            M, K, N
        );

        // Check for CUDA errors
        cudaError_t err = cudaGetLastError();
        if (err != cudaSuccess) {
            throw std::runtime_error(cudaGetErrorString(err));
        }

        // Synchronize to ensure kernel completes
        cudaDeviceSynchronize();
    } else {
        // Fall back to torch.matmul for other cases
        C = torch::matmul(A, B);
    }

    return C;
}
"""

optimized_matmul_cpp_source = """
torch::Tensor optimized_matmul_cuda(torch::Tensor A, torch::Tensor B);
"""

# Compile the inline CUDA code
optimized_matmul = load_inline(
    name="optimized_matmul",
    cpp_sources=optimized_matmul_cpp_source,
    cuda_sources=tall_skinny_matmul_source,
    functions=["optimized_matmul_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[],
)

class ModelNew(nn.Module):
    """
    Optimized model with custom CUDA kernel for tall-skinny matrix multiplication
    """
    def __init__(self):
        super(ModelNew, self).__init__()
        self.optimized_matmul = optimized_matmul

    def forward(self, A, B):
        """
        Performs optimized matrix multiplication with custom CUDA kernel.

        Args:
            A (torch.Tensor): Input matrix of shape (M, K)
            B (torch.Tensor): Input matrix of shape (K, N)

        Returns:
            torch.Tensor: Output matrix of shape (M, N)
        """
        return self.optimized_matmul.optimized_matmul_cuda(A, B)

